import React, { useState } from 'react';
import { GatsbyImage } from 'gatsby-plugin-image';
import Box from '@mui/material/Box';

const SectionMainvisual = data => {
  const img = data.images.allFile.edges;

  const [current, setCurrent] = useState(0);
  const [willShow, setWillShow] = useState(true);

  const [gatsbyImageData, setGatsbyImageData] = useState(
    img[current].node.childImageSharp.gatsbyImageData
  );
  const [gatsbyImageData2, setGatsbyImageData2] = useState(
    img[current + 1]?.node?.childImageSharp?.gatsbyImageData
  );

  const [isPortrait, setIsPortrait] = useState(
    gatsbyImageData.width < gatsbyImageData.height
  );
  const [isPortrait2, setIsPortrait2] = useState(
    gatsbyImageData2.width < gatsbyImageData2.height
  );

  const onTransitionEnd = () => {
    if (!willShow) {
      const _current = current >= img.length - 1 ? 0 : current + 1;
      const _next = _current + 1 >= img.length ? 0 : _current + 1;

      console.log(_current, _next);

      const _gatsbyImageData =
        img[_current].node.childImageSharp.gatsbyImageData;
      const _gatsbyImageData2 = img[_next].node.childImageSharp.gatsbyImageData;

      setGatsbyImageData(_gatsbyImageData);
      setGatsbyImageData2(_gatsbyImageData2);

      setIsPortrait(_gatsbyImageData.width < _gatsbyImageData.height);
      setIsPortrait2(_gatsbyImageData2.width < _gatsbyImageData2.height);

      setCurrent(_current);

      setTimeout(() => {
        console.log('timeout');
        setWillShow(true);
      }, 100);
    } else {
      setTimeout(() => {
        setWillShow(false);
      }, 5000);
    }
  };

  return (
    <Box
      component='section'
      sx={{
        position: 'relative',
        display: 'flex',
        justifyContent: 'center',
        alignItems: 'center',
        mt: '68px',
        // @TODO
        width: '100%',
        minHeight: {
          md: isPortrait ? 'auto' : '768px',
          sm: 'auto',
          xs: 'auto'
        },
        height: '100vh',
        height: '100dvh'
      }}
    >
      <Box
        onTransitionEnd={onTransitionEnd}
        sx={{
          position: 'absolute',
          width: {
            md: isPortrait ? '50%' : '100%',
            sm: '100%'
          },
          height: '100%',
          top: 0,
          zIndex: 5,
          transition: 'opacity 1000ms ease-out',
          opacity: willShow ? 1 : 0
        }}
      >
        <GatsbyImage
          image={gatsbyImageData}
          alt='YUHEI ONO'
          layout='fullWidth'
          placeholder='blurred'
        />
      </Box>
      <Box
        sx={{
          position: 'absolute',
          width: {
            md: isPortrait2 ? '50%' : '100%',
            sm: '100%'
          },
          height: '100%',
          top: 0,
          zIndex: -1,
          opacity: 0
        }}
      >
        <GatsbyImage
          image={gatsbyImageData2}
          alt='Preload'
          layout='fullWidth'
          placeholder='blurred'
        />
      </Box>
    </Box>
  );
};

export default SectionMainvisual;
